  1	import {
  2	  Chip,
  3	  ChipGroup,
  4	  Flex,
  5	  FlexItem,
  6	  SelectGroup,
  7	  SelectOption,
  8	  SelectList,
  9	} from "@patternfly/react-core";
 10	import { NodeKind } from "copiedFromConsole/types/node";
 11	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 12	import * as React from "react";
 13	import { uniq, flatten } from "lodash-es";
 14	import { useField } from "formik";
 15	import MultiSelectField from "components/shared/MultiSelectField";
 16	import {
 17	  getClusterRoleLabels,
 18	  Role,
 19	  getRoleTitle,
 20	  getRoleLabel,
 21	} from "data/nodeRoles";
 22	import fuzzy from "fuzzysearch";
 23	
 24	const stringifyNodeLabels = (node: NodeKind): string[] => {
 25	  if (!node.metadata?.labels) {
 26	    return [];
 27	  }
 28	  return Object.entries(node.metadata.labels).map(([key, value]) =>
 29	    value ? `${key}=${value}` : key
 30	  );
 31	};
 32	
 33	const LabelSelectionField = ({
 34	  allNodes,
 35	  isLoading,
 36	  fieldName,
 37	}: {
 38	  isLoading: boolean;
 39	  allNodes: NodeKind[];
 40	  fieldName: string;
 41	}) => {
 42	  const { t } = useNodeHealthCheckTranslation();
 43	  const [field, , { setValue }] = useField<string[]>(fieldName);
 44	  const [filterValue, setFilterValue] = React.useState<string>("");
 45	
 46	  const { roleLabels, otherLabels, selectedRoleLabels } = React.useMemo(() => {
 47	    // add previous selections too
 48	    const nodeLabels = uniq([
 49	      ...flatten(allNodes.map((node) => stringifyNodeLabels(node))),
 50	      ...field.value,
 51	    ]).sort();
 52	
 53	    const filteredNodeLabels = nodeLabels.filter((l) => fuzzy(filterValue, l));
 54	    const roleLabels = getClusterRoleLabels(t, filteredNodeLabels);
 55	
 56	    const otherLabels = filteredNodeLabels.filter(
 57	      (l) => !roleLabels.some(({ value }) => value === l)
 58	    );
 59	
 60	    const selectedRoleLabels = field.value.filter((l) =>
 61	      roleLabels.some(({ value }) => value === l)
 62	    );
 63	
 64	    return { roleLabels, otherLabels, selectedRoleLabels };
 65	  }, [isLoading, field.value, filterValue, t]);
 66	
 67	  const onDeleteLabel = (label: string) => {
 68	    setValue(field.value.filter((curLabel) => curLabel !== label));
 69	  };
 70	
 71	  return (
 72	    <>
 73	      <MultiSelectField
 74	        isLoading={isLoading}
 75	        name={fieldName}
 76	        label={t("Selector labels")}
 77	        helpText={t(
 78	          "Select the labels that will be used to find unhealthy nodes for remediation. The nodes must satisfy all selected labels."
 79	        )}
 80	        isRequired
 81	        filterValue={filterValue}
 82	        setFilterValue={setFilterValue}
 83	      >
 84	        {!!roleLabels.length && (
 85	          <SelectGroup label={t("Role")}>
 86	            <SelectList>
 87	              {roleLabels.map(({ title, value }) => (
 88	                <SelectOption
 89	                  key={value}
 90	                  isSelected={field.value.includes(value)}
 91	                  hasCheckbox
 92	                  value={value}
 93	                >
 94	                  {title}
 95	                </SelectOption>
 96	              ))}
 97	            </SelectList>
 98	          </SelectGroup>
 99	        )}
100	        <SelectGroup label={t("Labels")}>
101	          <SelectList>
102	            {otherLabels.map((label) => (
103	              <SelectOption
104	                key={label}
105	                isSelected={field.value.includes(label)}
106	                hasCheckbox
107	                value={label}
108	              >
109	                {label}
110	              </SelectOption>
111	            ))}
112	          </SelectList>
113	        </SelectGroup>
114	      </MultiSelectField>
115	      {!isLoading && (
116	        <Flex flexWrap={{ default: "nowrap" }}>
117	          {selectedRoleLabels.length > 0 && (
118	            <FlexItem>
119	              <ChipGroup
120	                key="roles"
121	                categoryName={t("Role")}
122	                collapsedText={t("Show more")}
123	                expandedText={t("Show less")}
124	                defaultIsOpen
125	              >
126	                {selectedRoleLabels.map((label) => (
127	                  <Chip key={label} onClick={() => onDeleteLabel(label)}>
128	                    {label === getRoleLabel(Role.WORKER)
129	                      ? getRoleTitle(t, Role.WORKER)
130	                      : getRoleTitle(t, Role.CONTROL_PLANE)}
131	                  </Chip>
132	                ))}
133	              </ChipGroup>
134	            </FlexItem>
135	          )}
136	          <FlexItem>
137	            <ChipGroup
138	              key="labels"
139	              categoryName={t("Labels")}
140	              collapsedText={t("Show more")}
141	              expandedText={t("Show less")}
142	              defaultIsOpen
143	              numChips={2}
144	            >
145	              {field.value.map((label) => (
146	                <Chip key={label} onClick={() => onDeleteLabel(label)}>
147	                  {label}
148	                </Chip>
149	              ))}
150	            </ChipGroup>
151	          </FlexItem>
152	        </Flex>
153	      )}
154	    </>
155	  );
156	};
157	
158	export default LabelSelectionField;

